import{_ as e,a as t,b as o,c as i}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as d,o as n,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Dodawanie kanału S3","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/upload/s3.md","filePath":"pl-PL/upload/s3.md","lastUpdated":1781962217000}'),c={name:"pl-PL/upload/s3.md"};function r(p,a,z,u,y,w){return n(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="dodawanie-kanału-s3" tabindex="-1">Dodawanie kanału S3 <a class="header-anchor" href="#dodawanie-kanału-s3" aria-label="Permalink to &quot;Dodawanie kanału S3&quot;">​</a></h1><h2 id="kiedy-warto-go-uzyc" tabindex="-1">Kiedy warto go użyć <a class="header-anchor" href="#kiedy-warto-go-uzyc" aria-label="Permalink to &quot;Kiedy warto go użyć&quot;">​</a></h2><p>Użyj kanału S3, gdy:</p><ul><li>chcesz podłączyć dowolną pamięć obiektową zgodną z S3, taką jak Cloudflare R2, Backblaze B2, MinIO, AWS S3 albo inny zgodny dostawca.</li><li>wolisz standardowy model konfiguracji S3: <code>Endpoint</code>, Access Key i Secret Key.</li><li>nie chcesz używać natywnego kanału Cloudflare R2 przez binding albo Twój dostawca nie jest Cloudflare R2.</li></ul><h2 id="co-przygotowac-przed-rozpoczeciem" tabindex="-1">Co przygotować przed rozpoczęciem <a class="header-anchor" href="#co-przygotowac-przed-rozpoczeciem" aria-label="Permalink to &quot;Co przygotować przed rozpoczęciem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Wymaganie</th><th>Cel</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>Endpoint API S3 usługi pamięci obiektowej.</td></tr><tr><td>Nazwa bucketu</td><td>Bucket, w którym będą przechowywane pliki.</td></tr><tr><td>Region</td><td>Region pamięci. Dla Cloudflare R2 zwykle <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>Identyfikator klucza dostępu S3.</td></tr><tr><td>Secret Access Key</td><td>Tajny klucz dostępu S3.</td></tr><tr><td>Domena CDN</td><td>Opcjonalna własna domena dostępu do plików.</td></tr></tbody></table><p>Przykład dla Cloudflare R2 przez API S3:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: skopiowany z tokenu API Cloudflare R2</span></span>
<span class="line"><span>Secret Access Key: skopiowany z tokenu API Cloudflare R2</span></span></code></pre></div><h2 id="gdzie-dodac-kanał" tabindex="-1">Gdzie dodać kanał <a class="header-anchor" href="#gdzie-dodac-kanał" aria-label="Permalink to &quot;Gdzie dodać kanał&quot;">​</a></h2><ol><li>Otwórz Ustawienia systemowe.</li><li>Przejdź do Ustawień przesyłania.</li><li>Kliknij Dodaj kanał w prawym górnym rogu.</li><li>Wybierz <code>S3</code>.</li></ol><h2 id="opis-pol" tabindex="-1">Opis pól <a class="header-anchor" href="#opis-pol" aria-label="Permalink to &quot;Opis pól&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pole</th><th>Działanie</th><th>Wymagane</th></tr></thead><tbody><tr><td>Nazwa kanału</td><td>Czytelna nazwa kanału S3, np. <code>s3test</code> lub <code>R2-S3</code>.</td><td>Tak</td></tr><tr><td>Włącz kanał</td><td>Określa, czy kanał bierze udział w wyborze kanału uploadu.</td><td>Zalecane</td></tr><tr><td>Endpoint</td><td>Pełny endpoint usługi S3, z <code>https://</code>.</td><td>Tak</td></tr><tr><td>Własna domena CDN</td><td>Opcjonalnie. Po ustawieniu wygenerowane linki plików preferują tę domenę.</td><td>Nie</td></tr><tr><td>Nazwa bucketu</td><td>Nazwa bucketu, np. <code>s3test</code> lub <code>img-r2</code>.</td><td>Tak</td></tr><tr><td>Region bucketu</td><td>Region. Dla Cloudflare R2 zwykle <code>auto</code>.</td><td>Tak</td></tr><tr><td>Access Key ID</td><td>Identyfikator klucza S3.</td><td>Tak</td></tr><tr><td>Secret Access Key</td><td>Tajny klucz S3.</td><td>Tak</td></tr><tr><td>Path-style access</td><td>Przełącznik zgodności. Domyślnie wyłączony. Niektóre usługi MinIO, OpenList lub samodzielnie hostowane S3 mogą go wymagać.</td><td>Nie</td></tr><tr><td>Limit pojemności</td><td>Określa, czy kanał jest wybierany na podstawie dostępnej pojemności.</td><td>Nie</td></tr><tr><td>Limit rozmiaru</td><td>Wymagany po włączeniu limitu pojemności, np. <code>10 GB</code>.</td><td>Wymagany przy limicie</td></tr><tr><td>Próg</td><td>Zatrzymuje zapis po osiągnięciu tego procentu, np. <code>90%</code>.</td><td>Wymagany przy limicie</td></tr><tr><td>Uwaga</td><td>Notatki do własnego utrzymania.</td><td>Nie</td></tr></tbody></table><h2 id="tworzenie-kluczy-cloudflare-r2-s3-api" tabindex="-1">Tworzenie kluczy Cloudflare R2 S3 API <a class="header-anchor" href="#tworzenie-kluczy-cloudflare-r2-s3-api" aria-label="Permalink to &quot;Tworzenie kluczy Cloudflare R2 S3 API&quot;">​</a></h2><ol><li>Otwórz Cloudflare Dashboard.</li><li>Przejdź do <code>R2 Object Storage</code>.</li><li>Znajdź <code>Manage R2 API Tokens</code> albo wejście do zarządzania tokenami API.</li></ol><p>![Wejście do tokenów API R2](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>Utwórz token API R2 z dostępem do docelowego bucketu.</li></ol><p><img src="`+e+'" alt="Utwórz token API konta" loading="lazy"></p><ol start="5"><li>Skopiuj wygenerowane <code>Access Key ID</code> i <code>Secret Access Key</code>.</li></ol><p><img src="'+t+'" alt="Kopiowanie wartości tokenu" loading="lazy"></p><ol start="6"><li>Wróć na stronę bucketu R2 i potwierdź nazwę bucketu.</li><li>Zapisz endpoint API S3 konta. Zwykle wygląda tak:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="kroki-konfiguracji" tabindex="-1">Kroki konfiguracji <a class="header-anchor" href="#kroki-konfiguracji" aria-label="Permalink to &quot;Kroki konfiguracji&quot;">​</a></h2><ol><li>Otwórz Ustawienia przesyłania.</li><li>Kliknij Dodaj kanał.</li><li>Wybierz <code>S3</code>.</li><li>Wpisz rozpoznawalną nazwę kanału, np. <code>s3test</code>.</li><li>Wpisz endpoint API S3 w polu <code>Endpoint</code>.</li><li>Jeśli używasz własnego CDN, wpisz go w <code>Custom CDN domain</code>; w przeciwnym razie zostaw puste.</li><li>Wpisz nazwę bucketu.</li><li>Wpisz region. Dla przykładu Cloudflare R2 użyj <code>auto</code>.</li><li>Wpisz Access Key ID i Secret Access Key.</li><li>Zostaw Path-style access wyłączony, chyba że dostawca wyraźnie go wymaga.</li><li>Jeśli chcesz kontrolę pojemności, włącz limit i wpisz limit oraz próg.</li><li>Kliknij Zapisz.</li></ol><p><img src="'+o+'" alt="Dodaj konfigurację S3" loading="lazy"></p><h2 id="jak-sprawdzic" tabindex="-1">Jak sprawdzić <a class="header-anchor" href="#jak-sprawdzic" aria-label="Permalink to &quot;Jak sprawdzić&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrola</th><th>Jak sprawdzić</th></tr></thead><tbody><tr><td>Karta kanału jest widoczna</td><td>Po zapisaniu w Ustawieniach przesyłania powinna pojawić się karta S3.</td></tr><tr><td>Kanał jest włączony</td><td>Przełącznik w prawym górnym rogu karty pozostaje włączony.</td></tr><tr><td>Ważne pola są zapisane</td><td>Widok szczegółów pokazuje Endpoint, Bucket, Region, Path-style access i powiązane pola.</td></tr><tr><td>Upload działa</td><td>Prześlij obraz testowy i sprawdź, czy obiekt pojawił się w docelowym buckecie.</td></tr><tr><td>Link otwiera się</td><td>Link obrazu zwrócony po uploadzie otwiera się normalnie.</td></tr><tr><td>Pojemność działa</td><td>Jeśli limit jest włączony, karta pokazuje użycie i ustawiony limit.</td></tr></tbody></table><p>Statystyki pojemności S3 są liczone z lokalnych rekordów plików ImgBed, a nie przez odpytywanie bucketu dostawcy w czasie rzeczywistym. Po zapisaniu konfiguracji S3 system przelicza stan limitu na podstawie bieżących rekordów D1.</p><p><img src="'+i+`" alt="Zapytanie o limit zakończone powodzeniem" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="czy-właczac-path-style-access" tabindex="-1">Czy włączać Path-style access? <a class="header-anchor" href="#czy-właczac-path-style-access" aria-label="Permalink to &quot;Czy włączać Path-style access?&quot;">​</a></h3><p>Zwykle nie.</p><p>Włącz tylko wtedy, gdy dostawca zgodny z S3 nie obsługuje adresów virtual-hosted-style albo dokumentacja dostawcy wyraźnie wymaga path-style access. Niektóre endpointy MinIO, samodzielnie hostowane S3 i zgodne z OpenList mogą tego potrzebować.</p><h3 id="do-czego-słuzy-domena-cdn" tabindex="-1">Do czego służy domena CDN? <a class="header-anchor" href="#do-czego-słuzy-domena-cdn" aria-label="Permalink to &quot;Do czego służy domena CDN?&quot;">​</a></h3><p>Jeśli przed bucketem używasz CDN lub własnej domeny dostępowej, wpisz ją tutaj.</p><p>Po konfiguracji wygenerowane linki plików będą preferować tę domenę. Jeśli nie używasz CDN, zostaw pole puste.</p><h3 id="dlaczego-upload-sie-nie-udaje" tabindex="-1">Dlaczego upload się nie udaje? <a class="header-anchor" href="#dlaczego-upload-sie-nie-udaje" aria-label="Permalink to &quot;Dlaczego upload się nie udaje?&quot;">​</a></h3><p>Najpierw sprawdź:</p><ol><li>Endpoint zawiera pełny URL z <code>https://</code>.</li><li>Nazwa bucketu jest poprawna.</li><li>Region pasuje do wymagań dostawcy.</li><li>Access Key ID i Secret Access Key zostały skopiowane w całości.</li><li>Klucz ma uprawnienia zapisu do docelowego bucketu.</li><li>Dostawca nie wymaga Path-style access albo opcja została włączona, jeśli jest wymagana.</li></ol><h2 id="szybka-lista" tabindex="-1">Szybka lista <a class="header-anchor" href="#szybka-lista" aria-label="Permalink to &quot;Szybka lista&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Przygotuj S3 Endpoint, Bucket, Region, Access Key i Secret Key</span></span>
<span class="line"><span>-&gt; Otwórz Ustawienia przesyłania</span></span>
<span class="line"><span>-&gt; Dodaj kanał</span></span>
<span class="line"><span>-&gt; Wybierz S3</span></span>
<span class="line"><span>-&gt; Wpisz Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; Wpisz domenę CDN, jeśli potrzeba</span></span>
<span class="line"><span>-&gt; Domyślnie zostaw Path-style access wyłączony</span></span>
<span class="line"><span>-&gt; Włącz limit pojemności, jeśli potrzeba</span></span>
<span class="line"><span>-&gt; Zapisz</span></span>
<span class="line"><span>-&gt; Prześlij obraz testowy i sprawdź wynik</span></span></code></pre></div>`,40)])])}const m=d(c,[["render",r]]);export{g as __pageData,m as default};
